import React, { useEffect, useState } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';

export default function BrowsePage() {
  const { API } = useAuth();
  const [searchParams, setSearchParams] = useSearchParams();
  const [movies, setMovies] = useState([]);
  const [genres, setGenres] = useState([]);
  const [loading, setLoading] = useState(false);

  const search = searchParams.get('search') || '';
  const sort = searchParams.get('sort') || 'popular';
  const genre = searchParams.get('genre') || 'All';

  useEffect(() => {
    axios
      .get(`${API}/movies/genres`)
      .then((res) => setGenres(res.data || ['All']))
      .catch(() => setGenres(['All']));
  }, [API]);

  useEffect(() => {
    setLoading(true);
    const params = { sort, search, limit: 50 };
    if (genre && genre !== 'All') params.genre = genre;

    axios
      .get(`${API}/movies`, { params })
      .then((res) => setMovies(res.data.movies || []))
      .catch(() => setMovies([]))
      .finally(() => setLoading(false));
  }, [API, search, sort, genre]);

  const setSort = (nextSort) => {
    const next = new URLSearchParams(searchParams);
    next.set('sort', nextSort);
    setSearchParams(next);
  };

  const setGenreFilter = (nextGenre) => {
    const next = new URLSearchParams(searchParams);
    next.set('genre', nextGenre);
    setSearchParams(next);
  };

  return (
    <main className="page" style={{ padding: '100px 24px 32px' }}>
      <section className="section" style={{ display: 'flex', justifyContent: 'space-between', gap: '12px', flexWrap: 'wrap', alignItems: 'center' }}>
        <h1 className="section-title" style={{ marginBottom: 0 }}>Browse</h1>
        <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
          {['popular', 'rating', 'year'].map((item) => (
            <button
              key={item}
              className={`genre-pill ${sort === item ? 'active' : ''}`}
              onClick={() => setSort(item)}
            >
              {item}
            </button>
          ))}
        </div>
      </section>

      <section className="section" style={{ paddingTop: '0' }}>
        <h3 style={{ fontSize: '0.9rem', textTransform: 'uppercase', letterSpacing: '1px', color: 'var(--text-dim)', marginBottom: '12px' }}>Genre</h3>
        <div style={{ display: 'flex', gap: '8px', flexWrap: 'wrap' }}>
          {genres.map((genreItem) => (
            <button
              key={genreItem}
              className={`genre-pill ${genre === genreItem ? 'active' : ''}`}
              onClick={() => setGenreFilter(genreItem)}
            >
              {genreItem}
            </button>
          ))}
        </div>
      </section>

      {loading ? (
        <div style={{ padding: '40px', textAlign: 'center' }}>Loading movies...</div>
      ) : (
        <section style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(180px, 1fr))', gap: '14px' }}>
          {movies.length > 0 ? (
            movies.map((movie) => (
              <Link key={movie._id} to={`/movie/${movie._id}`} className="movie-card" style={{ height: '280px' }}>
                <img src={movie.thumbnail} alt={movie.title} loading="lazy" />
                <div className="card-overlay">
                  <div className="card-title">{movie.title}</div>
                </div>
              </Link>
            ))
          ) : (
            <div style={{ gridColumn: '1 / -1', textAlign: 'center', padding: '40px', color: 'var(--text-dim)' }}>
              No movies found
            </div>
          )}
        </section>
      )}
    </main>
  );
}
